using System.Collections;
using UnityEngine;

/// <summary>
/// Habilidade de Investida (CHG do GDD).
///
/// - Dentro de água, se a forma estiver com WaterMotor2D.IsActive (forma
///   aquática + dentro de água — ex.: Orca), StartCharge() dispara a
///   "investida aquática" via WaterMotor2D.StartAquaticCharge(), reutilizando
///   dashSpeed/dashDuration da ficha (AnimalFormData).
/// - Em terra, StartCharge() dispara uma investida horizontal na direcção em
///   que o player está virado (chargeSpeed/chargeDuration/chargeCooldown da
///   ficha), bloqueando o movimento normal enquanto dura e activando
///   motor.SetDashing(true) — o dano de contacto chega "de borla" via
///   PlayerAttack.damageWhileDashing, tal como na investida aquática
///   (Cavalo/Cervo/Elefante/Onça e outros animais com PrimaryAbility.Charge).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class ChargeAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private bool enabledForForm;
    private AnimalFormData form;
    private WaterMotor2D waterMotor;
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private float cooldownTimer;
    private Coroutine chargeRoutine;

    private void Awake()
    {
        waterMotor = GetComponent<WaterMotor2D>();
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && (form.canCharge || form.primaryAbility == PrimaryAbility.Charge);

        if (!enabledForForm) StopChargeIfRunning();
    }

    public void StartCharge()
    {
        if (!enabledForForm) return;

        // Investida aquática (Orca, Tarefa #14): reutiliza as estatísticas de
        // Dash da ficha. O dano de contacto vem "de borla" via
        // PlayerAttack.damageWhileDashing (motor.SetDashing(true)).
        if (waterMotor != null && waterMotor.IsActive)
        {
            waterMotor.StartAquaticCharge(form.dashSpeed, form.dashDuration);
            return;
        }

        // Investida em terra (Cavalo/Cervo/Elefante/Onça, etc.).
        if (cooldownTimer > 0f) return;
        if (chargeRoutine != null) return;
        if (motor.MovementLocked) return;
        if (!motor.IsGrounded) return;

        chargeRoutine = StartCoroutine(ChargeRoutine());
    }

    private IEnumerator ChargeRoutine()
    {
        cooldownTimer = form.chargeCooldown;

        motor.SetMovementLocked(true, this);
        motor.SetDashing(true);

        int dir = motor.FacingSign != 0 ? motor.FacingSign : 1;

        float elapsed = 0f;
        while (elapsed < form.chargeDuration)
        {
            rb.linearVelocity = new Vector2(dir * form.chargeSpeed, rb.linearVelocity.y);
            elapsed += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        EndCharge();
    }

    private void EndCharge()
    {
        motor.SetDashing(false);
        motor.SetMovementLocked(false, this);
        chargeRoutine = null;
    }

    private void StopChargeIfRunning()
    {
        if (chargeRoutine == null) return;

        StopCoroutine(chargeRoutine);
        EndCharge();
    }

    public void ReleaseCharge()
    {
        if (!enabledForForm) return;
        if (waterMotor != null && waterMotor.IsActive) return; // investida aquática termina por tempo, não por soltar.

        // Investida em terra também termina por tempo (ChargeRoutine), não por soltar.
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    void IAbility.Activate() => StartCharge();
    void IAbility.Release() => ReleaseCharge();

    /// <summary>
    /// Cancela a investida em curso — aquática (WaterMotor2D.EndAquaticCharge)
    /// ou em terra (pára a ChargeRoutine e restaura movimento). Chamado por
    /// AbilityRouter.CancelAll (ex.: PlayerDeathHandler na morte,
    /// transformação a meio da investida).
    /// </summary>
    public void Cancel(AbilityCancelReason reason)
    {
        if (waterMotor != null) waterMotor.EndAquaticCharge();
        StopChargeIfRunning();
    }

    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => chargeRoutine != null;
    public float CooldownDuration => form != null ? form.chargeCooldown : 0f;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && chargeRoutine == null && !motor.MovementLocked;

    /// <summary>AnimalsDebugPanel — zera o cooldown da investida.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
